const headers = $input.item.json.headers || {};
const body    = $input.item.json.body    || {};
const auth    = headers['authorization'] || headers['Authorization'] || '';
const token   = auth.toLowerCase().startsWith('bearer ') ? auth.slice(7).trim() : '';
if (!token) return { json: { ok: false, status: 401, error: 'Missing session token' } };

const f = body.filters || {};
const limit = Math.min(Math.max(parseInt(f.limit, 10) || 100, 1), 500);
const sinceIso = f.since || null;

function qsBase(orderCol) {
  const parts = ['order=' + orderCol + '.desc', 'limit=' + limit];
  if (sinceIso) parts.push(orderCol + '=gte.' + encodeURIComponent(sinceIso));
  return parts;
}

// Drafts: in_progress unless user explicitly asked
const qsDrafts = ['select=id,template_id,industry_slug,client_id,lead_id,email,full_name,company,phone,preview_monthly_cents,preview_total_cents,step,status,resume_token,created_at,updated_at']
  .concat(qsBase('updated_at'));
if (f.status && f.status !== 'all') qsDrafts.push('status=eq.' + encodeURIComponent(f.status));
if (f.industry_slug) qsDrafts.push('industry_slug=eq.' + encodeURIComponent(f.industry_slug));

// Completed: any status by default; status filter narrows
const qsCompleted = ['select=id,draft_id,template_id,industry_slug,client_id,lead_id,email,full_name,company,phone,base_tier,base_monthly_cents,total_monthly_cents,total_one_time_cents,total_first_year_cents,status,expires_at,sent_at,viewed_at,accepted_at,declined_at,decline_reason,pdf_url,created_at']
  .concat(qsBase('created_at'));
if (f.status && f.status !== 'all') qsCompleted.push('status=eq.' + encodeURIComponent(f.status));
if (f.industry_slug) qsCompleted.push('industry_slug=eq.' + encodeURIComponent(f.industry_slug));

return { json: {
  token: token,
  qs_drafts: qsDrafts.join('&'),
  qs_completed: qsCompleted.join('&'),
  qs_templates: 'select=id,industry_slug,industry_name,vertical_id,emoji,active,sort_order&order=sort_order.asc',
  filters: f,
  limit: limit
} };

const rows = $input.item.json;
const row  = Array.isArray(rows) ? (rows[0] || null) : (rows && (rows.user_id || rows.id) ? rows : null);
if (!row) return { json: { ok: false, status: 401, error: 'Invalid or expired session' } };
if (row.user_role !== 'admin') return { json: { ok: false, status: 403, error: 'Admin access required' } };
const x = $('Extract Inputs').item.json;
return { json: { ok: true, qs_drafts: x.qs_drafts, qs_completed: x.qs_completed, qs_templates: x.qs_templates, filters: x.filters } };

const allOf = function (name) {
  try {
    const items = $(name).all().map(function (i) { return i.json; });
    if (items.length === 1 && Array.isArray(items[0])) return items[0];
    if (items.length === 1 && items[0] && typeof items[0] === 'object' && !Array.isArray(items[0]) && items[0].id) return [items[0]];
    return items.filter(function (x) { return x && x.id; });
  } catch (e) { return []; }
};

const drafts    = allOf('Query Drafts');
const completed = allOf('Query Completed');
const templates = allOf('Query Templates');

// Stats for the KPI strip
const inProgress    = drafts.filter(function (d) { return d.status === 'in_progress'; }).length;
const abandoned     = drafts.filter(function (d) { return d.status === 'abandoned'; }).length;
const quotesOpen    = completed.filter(function (q) { return q.status === 'open' || q.status === 'sent' || q.status === 'viewed'; }).length;
const quotesAccepted = completed.filter(function (q) { return q.status === 'accepted'; }).length;
const quotesDeclined = completed.filter(function (q) { return q.status === 'declined'; }).length;

const totalMonthlyAccepted = completed
  .filter(function (q) { return q.status === 'accepted'; })
  .reduce(function (s, q) { return s + (q.total_monthly_cents || 0); }, 0);

return { json: {
  ok: true,
  templates:  templates,
  drafts:     drafts,
  completed:  completed,
  stats: {
    drafts_in_progress: inProgress,
    drafts_abandoned:   abandoned,
    quotes_open:        quotesOpen,
    quotes_accepted:    quotesAccepted,
    quotes_declined:    quotesDeclined,
    monthly_revenue_committed_cents: totalMonthlyAccepted
  },
  filters: $('Check Admin').item.json.filters
} };
